 3→interface FormCheckboxProps {
 4→  label: string;
 5→  checked: boolean;
 6→  onChange: (checked: boolean) => void;
 7→  description?: string;
 8→}
 9→
10→export function FormCheckbox({
11→  label,
12→  checked,
13→  onChange,
14→  description,
15→}: FormCheckboxProps) {
16→  const id = useId();
17→
18→  return (
19→    <div className="form-checkbox">
20→      <div className="form-checkbox__row">
21→        <div
22→          className={`form-checkbox__box${checked ? ' form-checkbox__box--checked' : ''}`}
23→          role="checkbox"
24→          aria-checked={checked}
25→          tabIndex={0}
26→          id={id}
27→          onClick={() => onChange(!checked)}
28→          onKeyDown={e => {
29→            if (e.key === ' ' || e.key === 'Enter') {
30→              e.preventDefault();
31→              onChange(!checked);
32→            }
33→          }}
34→        >
35→          {checked && (
36→            <svg
37→              width="10"
38→              height="10"
39→              viewBox="0 0 10 10"
40→              fill="none"
41→              xmlns="http://www.w3.org/2000/svg"
