43→              <path
44→                d="M2 5L4.5 7.5L8 2.5"
45→                stroke="currentColor"
46→                strokeWidth="1.5"
47→                strokeLinecap="round"
48→                strokeLinejoin="round"
49→              />
50→            </svg>
51→          )}
52→        </div>
53→        <label className="form-checkbox__label" htmlFor={id}>
