166→export function App() {
167→  const [query, setQuery] = useState('');
168→  const [selectedIndex, setSelectedIndex] = useState(0);
169→  const [actionsOpen, setActionsOpen] = useState(false);
170→  const [drilledItem, setDrilledItem] = useState<ListItemData | null>(null);
171→  const [viewMode, setViewMode] = useState<ViewMode>('list');
172→  const [snippetForm, setSnippetForm] =
173→    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
174→  const { toasts, show: showToast, hide: hideToast } = useToast();
175→
176→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
177→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
178→  const filteredColors = useMemo(
179→    () => filterColors(MOCK_COLORS, query),
180→    [query],
181→  );
182→  const selectedItem =
183→    viewMode === 'list' ? (drilledItem ?? allItems[selectedIndex]) : undefined;
184→
185→  const handleQueryChange = useCallback((value: string) => {
186→    setQuery(value);
187→    setSelectedIndex(0);
188→    setActionsOpen(false);
189→  }, []);
190→
191→  const handleActiveIndexChange = useCallback((index: number) => {
192→    setSelectedIndex(index);
193→    setActionsOpen(false);
194→  }, []);
195→
196→  const handleDrillIn = useCallback(() => {
197→    const item = allItems[selectedIndex];
198→    if (item) {
199→      if (item.id === 'color-picker') {
200→        setViewMode('grid');
201→        setQuery('');
202→        setSelectedIndex(0);
203→        setActionsOpen(false);
204→        showToast({
205→          style: 'success',
206→          title: 'Opened Color Picker',
207→        });
208→      } else {
209→        setDrilledItem(item);
210→        setQuery('');
211→        setActionsOpen(false);
212→        showToast({
213→          style: 'success',
214→          title: `Opened ${item.title}`,
215→        });
216→      }
217→    }
218→  }, [
219→    allItems,
220→    selectedIndex,
221→    showToast,
222→  ]);
223→
224→  const handleDrillBack = useCallback(() => {
225→    setDrilledItem(null);
226→    setViewMode('list');
227→    setQuery('');
228→    setSelectedIndex(0);
229→    setActionsOpen(false);
230→    setSnippetForm(INITIAL_SNIPPET_FORM);
231→  }, []);
232→
233→  const handleOpenCreateSnippet = useCallback(() => {
234→    setViewMode('form');
235→    setQuery('');
236→    setSelectedIndex(0);
237→    setActionsOpen(false);
238→    setSnippetForm(INITIAL_SNIPPET_FORM);
239→  }, []);
240→
241→  const handleSubmitSnippet = useCallback(() => {
242→    if (!snippetForm.name.trim()) {
243→      showToast({
244→        style: 'error',
245→        title: 'Name is required',
246→      });
247→      return;
248→    }
249→    if (!snippetForm.snippet.trim()) {
250→      showToast({
251→        style: 'error',
252→        title: 'Snippet content is required',
253→      });
254→      return;
255→    }
256→    showToast({
257→      style: 'success',
258→      title: 'Snippet Created',
259→      message: snippetForm.name,
260→    });
261→    handleDrillBack();
262→  }, [
263→    snippetForm,
264→    showToast,
265→    handleDrillBack,
266→  ]);
267→
268→  const handleGridAction = useCallback(
269→    (index: number) => {
270→      const color = filteredColors[index];
271→      if (color) {
272→        showToast({
273→          style: 'info',
274→          title: 'Copied color',
275→          message: color.color,
276→        });
277→      }
278→    },
279→    [
280→      filteredColors,
281→      showToast,
282→    ],
283→  );
284→
285→  const breadcrumbs: BreadcrumbItem[] | undefined =
286→    viewMode === 'form'
287→      ? [
288→          {
289→            label: 'Raycast',
290→            onBack: handleDrillBack,
291→          },
292→          { label: 'Create Snippet' },
293→        ]
294→      : viewMode === 'grid'
295→        ? [
296→            {
297→              label: 'Raycast',
298→              onBack: handleDrillBack,
299→            },
300→            { label: 'Color Picker' },
301→          ]
302→        : drilledItem
303→          ? [
304→              {
305→                label: 'Raycast',
306→                onBack: handleDrillBack,
307→              },
308→              { label: drilledItem.title },
309→            ]
310→          : undefined;
311→
312→  const toggleActions = useCallback(() => {
313→    setActionsOpen(prev => !prev);
314→  }, []);
315→
316→  const closeActions = useCallback(() => {
317→    setActionsOpen(false);
318→  }, []);
319→
320→  useEffect(() => {
321→    function handleKeyDown(e: KeyboardEvent) {
322→      if (e.key === 'k' && e.metaKey) {
323→        e.preventDefault();
324→        setActionsOpen(prev => !prev);
325→        return;
326→      }
327→      if (e.key === 'Enter' && e.metaKey && viewMode === 'form') {
328→        e.preventDefault();
329→        handleSubmitSnippet();
330→        return;
331→      }
332→      if (e.key === 'n' && e.metaKey && viewMode !== 'form') {
333→        e.preventDefault();
334→        handleOpenCreateSnippet();
335→      }
336→    }
